       and fsi.backend_uri like #{criteria.backendUri,jdbcType=VARCHAR}




       and fsi.database_uri like #{criteria.databaseUri,jdbcType=VARCHAR}




       and fsi.enabled_flag = #{criteria.enabled,jdbcType=BIT}
